/* eslint-disable no-prototype-builtins, new-cap */
import { commandsByType } from './commands';
import Events from './Events';

export class History {
  constructor(editor) {
    this.editor = editor;
    this.undos = [];
    this.redos = [];
    this.lastCmdTime = Date.now();
    this.idCounter = 0;

    this.historyDisabled = false;

    Events.on('sceneplayingtoggle', (playing) => {
      this.historyDisabled = playing;
    });
  }

  execute(cmd, optionalName) {
    const lastCmd = this.undos[this.undos.length - 1];
    const timeDifference = Date.now() - this.lastCmdTime;

    const isUpdatableCmd =
      lastCmd &&
      lastCmd.updatable &&
      cmd.updatable &&
      lastCmd.entityId === cmd.entityId &&
      lastCmd.type === cmd.type &&
      lastCmd.component === cmd.component &&
      lastCmd.property === cmd.property;

    if (isUpdatableCmd && timeDifference < 500) {
      lastCmd.update(cmd);
      cmd = lastCmd;
    } else {
      // the command is not updatable and is added as a new part of the history

      this.undos.push(cmd);
      cmd.id = ++this.idCounter;
    }

    cmd.name = optionalName !== undefined ? optionalName : cmd.name;
    cmd.execute();
    cmd.inMemory = true;

    cmd.json = cmd.toJSON(); // serialize the cmd immediately after execution and append the json to the cmd

    this.lastCmdTime = Date.now();

    // clearing all the redo-commands

    this.redos = [];
    Events.emit('historychanged', cmd);
  }

  undo() {
    if (this.historyDisabled) {
      alert('Undo/Redo disabled while scene is playing.');
      return;
    }

    let cmd;

    if (this.undos.length > 0) {
      cmd = this.undos.pop();

      if (cmd.inMemory === false) {
        cmd.fromJSON(cmd.json);
      }
    }

    if (cmd !== undefined) {
      cmd.undo();
      cmd.json = cmd.toJSON();
      this.redos.push(cmd);
      Events.emit('historychanged', cmd);
    }

    return cmd;
  }

  redo() {
    if (this.historyDisabled) {
      alert('Undo/Redo disabled while scene is playing.');
      return;
    }

    let cmd;

    if (this.redos.length > 0) {
      cmd = this.redos.pop();

      if (cmd.inMemory === false) {
        cmd.fromJSON(cmd.json);
      }
    }

    if (cmd !== undefined) {
      cmd.execute();
      cmd.json = cmd.toJSON();
      this.undos.push(cmd);
      Events.emit('historychanged', cmd);
    }

    return cmd;
  }

  toJSON() {
    const history = {};
    history.undos = [];
    history.redos = [];

    // Append Undos to History
    for (let i = 0; i < this.undos.length; i++) {
      if (this.undos[i].hasOwnProperty('json')) {
        history.undos.push(this.undos[i].json);
      }
    }

    // Append Redos to History
    for (let i = 0; i < this.redos.length; i++) {
      if (this.redos[i].hasOwnProperty('json')) {
        history.redos.push(this.redos[i].json);
      }
    }

    return history;
  }

  fromJSON(json) {
    if (json === undefined) return;

    for (let i = 0; i < json.undos.length; i++) {
      const cmdJSON = json.undos[i];
      const cmd = new commandsByType.get(cmdJSON.type)(this.editor); // creates a new object of type "json.type"
      cmd.json = cmdJSON;
      cmd.id = cmdJSON.id;
      cmd.name = cmdJSON.name;
      this.undos.push(cmd);
    }

    for (let i = 0; i < json.redos.length; i++) {
      const cmdJSON = json.redos[i];
      const cmd = new commandsByType.get[cmdJSON.type](this.editor); // creates a new object of type "json.type"
      cmd.json = cmdJSON;
      cmd.id = cmdJSON.id;
      cmd.name = cmdJSON.name;
      this.redos.push(cmd);
    }

    // Select the last executed undo-command
    Events.emit('historychanged', this.undos[this.undos.length - 1]);
  }

  clear() {
    this.undos = [];
    this.redos = [];
    this.idCounter = 0;

    Events.emit('historychanged', null);
  }
}
